package be.schaubroeck.lpb.rkm.rekenmotor.rsz.dmfa.bijdrage.patronaal;

import be.schaubroeck.lpb.rkm.rekenmotor.LoonElement;
import be.schaubroeck.lpb.rkm.rekenmotor.RekenContext;
import be.schaubroeck.lpb.rkm.rekenmotor.RekenTijd;
import be.schaubroeck.lpb.rkm.rekenmotor.Take;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenPatronaalRszKey;
import be.schaubroeck.lpb.rkm.rekenmotor.util.ConstantManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.LoonElementManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.PersoonsDataManager;
import be.schaubroeck.lpb.rkm.rekenresultaat.service.util.RekenresultaatBedrag;
import be.schaubroeck.lpb.tools.MaandTotaal1;
import be.schaubroeck.lpb.tools.MaandTotaal3;
import be.schaubroeck.lpb.tools.Money;
import be.schaubroeck.lpb.tools.Opdracht;
import be.schaubroeck.lpb.tools.enumtypes.AkeTijdperk;
import be.schaubroeck.lpb.tools.enumtypes.Konstanten;
import lombok.AllArgsConstructor;
import lombok.Builder;
import lombok.NonNull;

import java.util.Set;

/*
  Bedoeling is om uiteindelijk alles wat met 1 bijdrage te maken heeft te centraliseren zodat er 1 class is per bijdrage die als vertrekpunt dient.
  Als er daan een probleem is met de bijdrage kan je het zeer snel vinden.
  Nieuwe bijdrage toevoegen is veel eenvoudiger en je kan niets meer vergeten.
  Verwacht ook dat veel van de KEYS en switches wegvallen

  Je krijgt dan:
    Bijdrage
    * MONEY_KEY_INHOUDING
    * REKENRESULTAAT_BEDRAG_INHOUDING
    * bereken()
    * getMaandTotaalBedrag(MaandTotaal1 mt1)
    * setMaandTotaalBedrag(MaandTotaal1 mt1, Money bedrag)

    BijdrageMetBasis extends Bijdrage
    * MONEY_KEY_BASIS
    * REKENRESULTAAT_BEDRAG_BASIS
    * getMaandTotaalBasis(MaandTotaal1 mt1)
    * setMaandTotaalBasis(MaandTotaal1 mt1, Money basis)
 */

@AllArgsConstructor
@Builder
public class Vakbondspremie {
    public static final int PREMIE_MONTH = 3;

    // Onderstaande laten staan. Je wil zeker zijn dat er een RekenresultaatBedrag is voor deze bijdrage.
    public static final RekenresultaatBedrag REKENRESULTAAT_BEDRAG_INHOUDING = RekenresultaatBedrag.PATRONALE_BIJDRAGE_VAKBONDSPREMIE;

    public static final Take TAKE = new Take(AkeTijdperk.DMFAPPL, 3, 1001, 223);

    @NonNull
    private final VakbondsPremieResultatenVoorwaarden resultatenVoorwaarden;
    @NonNull
    private final VakbondsPremieOpdracht vakbondsPremieOpdracht;

    @NonNull
    private final RekenContext mainContext;
    @NonNull
    private final ConstantManager constantManager;
    private final LoonElementManager loonElementManager;
    @NonNull
    private final RekenTijd rekenTijd;

    public static Vakbondspremie create(
            RekenContext mainContext, ConstantManager constantManager, PersoonsDataManager persoonsDataManager, LoonElementManager loonElementManager,
            RekenTijd rekenTijd,
            Set<Opdracht> opdrachten) {
        VakbondsPremieOpdracht vakbondsPremieOpdracht = new VakbondsPremieOpdracht(new VakbondspremieMraVoorwaarden(), opdrachten, rekenTijd);
        return Vakbondspremie.builder()
                .mainContext(mainContext)
                .constantManager(constantManager)
                .rekenTijd(rekenTijd)
                .resultatenVoorwaarden(new VakbondsPremieResultatenVoorwaarden(persoonsDataManager, loonElementManager, rekenTijd))
                .vakbondsPremieOpdracht(vakbondsPremieOpdracht)
                .build();
    }

    public void bereken() {
        if (rekenTijd.isRekenMonth(PREMIE_MONTH) && resultatenVoorwaarden.test()) {
            vakbondsPremieOpdracht.bepaal().ifPresent(this::zetVakbondsPremieOpLoonElement);
        }
    }

    private void zetVakbondsPremieOpLoonElement(Opdracht opdracht) {
        LoonElement element = mainContext.getOrCreateLoonElement(opdracht, TAKE);
        Money bijdrage = constantManager.getActualConstant(Konstanten.KST_VAKBONDSPREMIE, rekenTijd).getMoney();
        element.putProperty(RekenPatronaalRszKey.PATRONALE_BIJDRAGE_VAKBONDSPREMIE_KEY, bijdrage);
    }

    public static Money getMaandTotaalBedrag(MaandTotaal1 mt1) {
        MaandTotaal3 mt3 = mt1.getMaandTotaal3();
        return mt3.getInhoudingVakbondspremie();
    }

    public static void setMaandTotaalBedrag(MaandTotaal1 mt1, Money bedrag) {
        MaandTotaal3 mt3 = mt1.getMaandTotaal3();
        mt3.setInhoudingVakbondspremie(bedrag);
    }
}
